query:
START TRANSACTION;
UPDATE `products`
SET `sheetRowNumber` = `sheetRowNumber` - 1,
    `updatedAt` = CURRENT_TIMESTAMP
WHERE `archivedAt` IS NULL
  AND `poNumber` = 'PO-20260514-03'
  AND `stationCode` = 'A1'
  AND `productStatus` = 'pending_a1'
  AND `sheetRowNumber` BETWEEN 681 AND 777;
SELECT ROW_COUNT() AS `updatedRows`;
COMMIT;

